import React, { useState } from 'react';

function ShippingCalculator() {
  const [weight, setWeight] = useState('');
  const [itemType, setItemType] = useState('Hàng thường');
  const [totalCost, setTotalCost] = useState(0);
  const [showDiscount, setShowDiscount] = useState(false);

  const calculateShipping = () => {
    const kg = parseFloat(weight);
    if (isNaN(kg) || kg <= 0) {
      setTotalCost(0);
      setShowDiscount(false);
      return;
    }

    let rate = 0;
    switch (itemType) {
      case 'Hàng thường':
        rate = 260000;
        break;
      case 'Mỹ phẩm':
        rate = 300000;
        break;
      case 'Điện tử':
        setTotalCost('Liên hệ báo giá');
        setShowDiscount(false);
        return;
      default:
        rate = 260000;
    }

    let cost = kg * rate;
    if (kg > 5) {
      cost = kg * 250000;
      setShowDiscount(true);
    } else {
      setShowDiscount(false);
    }

    setTotalCost(cost.toLocaleString('vi-VN') + ' VNĐ');
  };

  return (
    <section className="bg-surface py-24 px-6 relative -mt-16 z-20 overflow-hidden">
      <div className="container mx-auto max-w-4xl bg-white p-10 md:p-16 rounded-2xl shadow-soft border border-gray-100 flex flex-col md:flex-row items-center gap-16 transition-all transform hover:shadow-2xl">
        <div className="md:w-1/2">
          <h2 className="text-4xl md:text-5xl font-serif font-extrabold text-primary-dark tracking-tight leading-tight">
            Tính toán cước phí nhanh
          </h2>
          <p className="mt-4 text-lg text-gray-500 font-sans font-light leading-relaxed">
            Ước tính chi phí vận chuyển của bạn chỉ trong vài giây với công cụ tính toán thông minh của Shipus.net.
          </p>
        </div>

        <div className="md:w-1/2 w-full space-y-8 bg-gray-50/50 p-8 rounded-xl border border-gray-100/50">
          <div className="text-left">
            <label htmlFor="weight" className="block text-gray-700 text-sm font-medium uppercase tracking-wider mb-2">Cân nặng (kg)</label>
            <input
              type="number"
              id="weight"
              className="w-full p-4 border-b-2 border-gray-200 bg-transparent rounded-none focus:outline-none focus:border-primary-accent text-xl font-bold transition-all text-primary-dark placeholder-gray-400"
              placeholder="0.00 kg"
              value={weight}
              onChange={(e) => setWeight(e.target.value)}
            />
          </div>

          <div className="text-left">
            <label htmlFor="itemType" className="block text-gray-700 text-sm font-medium uppercase tracking-wider mb-2">Loại hàng hóa</label>
            <select
              id="itemType"
              className="w-full p-4 border-b-2 border-gray-200 bg-transparent rounded-none focus:outline-none focus:border-primary-accent text-lg font-medium transition-all text-primary-dark appearance-none"
              value={itemType}
              onChange={(e) => setItemType(e.target.value)}
            >
              <option value="Hàng thường">Hàng thường (Quần áo, đồ gia dụng)</option>
              <option value="Mỹ phẩm">Mỹ phẩm, Nước hoa, Túi xách</option>
              <option value="Điện tử">Điện tử cao cấp (Laptop, iPhone)</option>
            </select>
          </div>

          <button
            onClick={calculateShipping}
            className="w-full bg-primary-dark hover:bg-black text-white font-bold py-4 px-8 rounded-md text-lg shadow-lg transition-all active:scale-95 uppercase tracking-widest"
          >
            TÍNH CƯỚC PHÍ
          </button>

          {totalCost !== 0 && (
            <div className="mt-10 p-6 bg-white border border-primary-accent/30 text-primary-dark rounded-xl shadow-inner animate-fade-in text-center">
              <p className="text-sm font-medium uppercase tracking-widest text-gray-400 mb-2">Tổng tiền dự tính</p>
              <p className="text-3xl font-serif font-extrabold text-primary-accent">{totalCost}</p>
              {showDiscount && (
                <p className="mt-3 text-xs text-orange-700 italic font-medium">✨ Giảm ưu đãi xuống 250.000đ/kg cho kiện hàng trên 5kg!</p>
              )}
            </div>
          )}
        </div>
      </div>
    </section>
  );
}

export default ShippingCalculator;
